import type { PathResult } from '@shared/pathfinding/types'
import type { NavFloor, NavNode } from '@shared/types'
import { useMemo } from 'react'

// ============================================================
// Types
// ============================================================

export type StepIcon =
  | 'straight'
  | 'turn-left'
  | 'turn-right'
  | 'sharp-left'
  | 'sharp-right'
  | 'arrive'
  | 'accessible'
  | 'stairs-up'
  | 'stairs-down'
  | 'elevator'
  | 'ramp'

export interface DirectionStep {
  /** Human-readable instruction, e.g. "Turn left at the cafeteria" */
  instruction: string
  icon: StepIcon
  /** Segment distance in normalized units (0–1 coordinate space) */
  distanceM: number
  /** Estimated seconds for this segment */
  durationSec: number
  /** True if this segment passes through a ramp or elevator node */
  isAccessibleSegment: boolean
}

export interface DirectionsResult {
  steps: DirectionStep[]
  /** Sum of all segment distances in normalized units */
  totalDistanceNorm: number
  /** Sum of all step durations in seconds */
  totalDurationSec: number
}

// ============================================================
// Constants
// ============================================================

const WALKING_SPEED_STANDARD = 0.023 // normalized units/s
const WALKING_SPEED_ACCESSIBLE = 0.013 // normalized units/s

/** Node types that are visible/searchable destinations — eligible for landmark references */
const LANDMARK_TYPES = new Set(['room', 'landmark', 'entrance', 'elevator', 'restroom'])

// ============================================================
// Private helpers
// ============================================================

/**
 * Compute compass bearing in degrees (0–360) from point A to point B.
 * Uses screen-space convention: x increases right, y increases down.
 * atan2(dx, -dy) gives a bearing where 0°=north, 90°=east, 180°=south, 270°=west.
 */
function bearing(ax: number, ay: number, bx: number, by: number): number {
  const dx = bx - ax
  const dy = by - ay
  // atan2(x, -y) → clockwise from north in screen-space
  const rad = Math.atan2(dx, -dy)
  const deg = (rad * 180) / Math.PI
  return (deg + 360) % 360
}

/**
 * Normalize an angle difference to the range [-180, 180].
 */
function normalizeDelta(delta: number): number {
  let d = delta % 360
  if (d > 180) d -= 360
  if (d < -180) d += 360
  return d
}

/**
 * Euclidean distance between two normalized coordinate points.
 */
function euclideanDist(ax: number, ay: number, bx: number, by: number): number {
  const dx = bx - ax
  const dy = by - ay
  return Math.sqrt(dx * dx + dy * dy)
}

/**
 * Classify bearing delta into a step icon.
 */
function classifyTurn(
  delta: number,
): Exclude<StepIcon, 'arrive' | 'accessible' | 'stairs-up' | 'stairs-down' | 'elevator' | 'ramp'> {
  const abs = Math.abs(delta)
  if (abs < 30) return 'straight'
  if (abs < 120) return delta > 0 ? 'turn-right' : 'turn-left'
  return delta > 0 ? 'sharp-right' : 'sharp-left'
}

/**
 * Build the instruction text for a direction step at the current (middle) node.
 * Appends " at the {label}" when the node is a searchable landmark-type.
 */
function buildInstruction(
  icon: Exclude<StepIcon, 'accessible' | 'stairs-up' | 'stairs-down' | 'elevator' | 'ramp'>,
  node: NavNode,
): string {
  const base: Record<
    Exclude<StepIcon, 'accessible' | 'stairs-up' | 'stairs-down' | 'elevator' | 'ramp'>,
    string
  > = {
    straight: 'Continue straight',
    'turn-left': 'Turn left',
    'turn-right': 'Turn right',
    'sharp-left': 'Sharp left',
    'sharp-right': 'Sharp right',
    arrive: `Arrive at ${node.label}`,
  }

  const text = base[icon]

  // For non-arrive steps: append landmark reference if the node is a visible, searchable destination
  if (icon !== 'arrive' && LANDMARK_TYPES.has(node.type) && node.searchable) {
    return `${text} at the ${node.label}`
  }

  return text
}

// ============================================================
// Core function
// ============================================================

/**
 * Convert an ordered list of node IDs into turn-by-turn walking directions.
 *
 * Algorithm:
 * - 0 or 1 nodes → empty result
 * - 2 nodes → single "arrive" step (no turn to compute)
 * - N nodes → for each triple (prev, curr, next): classify bearing delta → build step
 *             then append final "arrive" step for the last node
 */
export function generateDirections(
  nodeIds: string[],
  nodeMap: Map<string, NavNode>,
  mode: 'standard' | 'accessible',
  floorMap: Map<number, NavFloor> = new Map(),
): DirectionsResult {
  if (nodeIds.length < 2) {
    return { steps: [], totalDistanceNorm: 0, totalDurationSec: 0 }
  }

  const speed = mode === 'accessible' ? WALKING_SPEED_ACCESSIBLE : WALKING_SPEED_STANDARD
  const steps: DirectionStep[] = []
  let totalDistanceNorm = 0

  // Process intermediate nodes (all except the first and last)
  for (let i = 1; i < nodeIds.length - 1; i++) {
    // noUncheckedIndexedAccess: bounds are guaranteed by the for-loop condition
    const prevId = nodeIds[i - 1] as string
    const currId = nodeIds[i] as string
    const nextId = nodeIds[i + 1] as string

    // Nodes are guaranteed to be in the map when the caller provides valid IDs
    const prev = nodeMap.get(prevId)
    const curr = nodeMap.get(currId)
    const next = nodeMap.get(nextId)
    if (prev === undefined || curr === undefined || next === undefined) continue

    const distanceM = euclideanDist(prev.x, prev.y, curr.x, curr.y)
    const durationSec = distanceM / speed

    // Floor-change detection: check if curr→next crosses a floor boundary
    if (curr.floorId !== next.floorId) {
      // Determine direction icon based on connector type and vertical direction
      let icon: StepIcon
      if (curr.type === 'stairs') {
        icon = next.floorId > curr.floorId ? 'stairs-up' : 'stairs-down'
      } else if (curr.type === 'elevator') {
        icon = 'elevator'
      } else if (curr.type === 'ramp') {
        icon = 'ramp'
      } else {
        // Fallback: should not occur in a well-formed graph
        icon = 'stairs-up'
      }

      // Determine connector type name for instruction text
      const connectorTypeName =
        curr.type === 'elevator' ? 'elevator' : curr.type === 'ramp' ? 'ramp' : 'stairs'

      // Look up destination floor number; fall back to next.floorId if not in map
      const destFloor = floorMap.get(next.floorId)
      const floorNumber = destFloor?.floorNumber ?? next.floorId
      const instruction = `Take the ${connectorTypeName} to Floor ${floorNumber}`

      const isAccessibleSegment = curr.type === 'elevator' || curr.type === 'ramp'

      steps.push({ instruction, icon, distanceM, durationSec, isAccessibleSegment })
      totalDistanceNorm += distanceM
      continue
    }

    const inBearing = bearing(prev.x, prev.y, curr.x, curr.y)
    const outBearing = bearing(curr.x, curr.y, next.x, next.y)
    const delta = normalizeDelta(outBearing - inBearing)

    const icon = classifyTurn(delta)
    const instruction = buildInstruction(icon, curr)
    const isAccessibleSegment = curr.type === 'ramp' || curr.type === 'elevator'

    steps.push({ instruction, icon, distanceM, durationSec, isAccessibleSegment })
    totalDistanceNorm += distanceM
  }

  // Final "arrive" step — distance from second-to-last to last node
  const lastPrevId = nodeIds[nodeIds.length - 2] as string
  const lastId = nodeIds[nodeIds.length - 1] as string
  const lastPrev = nodeMap.get(lastPrevId)
  const last = nodeMap.get(lastId)
  if (lastPrev === undefined || last === undefined) {
    return { steps: [], totalDistanceNorm: 0, totalDurationSec: 0 }
  }

  const arriveDistance = euclideanDist(lastPrev.x, lastPrev.y, last.x, last.y)
  const arriveDuration = arriveDistance / speed
  const arriveInstruction = buildInstruction('arrive', last)

  steps.push({
    instruction: arriveInstruction,
    icon: 'arrive',
    distanceM: arriveDistance,
    durationSec: arriveDuration,
    isAccessibleSegment: last.type === 'ramp' || last.type === 'elevator',
  })

  totalDistanceNorm += arriveDistance
  const totalDurationSec = steps.reduce((sum, s) => sum + s.durationSec, 0)

  return { steps, totalDistanceNorm, totalDurationSec }
}

// ============================================================
// routesAreIdentical utility
// ============================================================

/**
 * Returns true only if both routes were found and share the exact same ordered node IDs.
 */
export function routesAreIdentical(a: PathResult, b: PathResult): boolean {
  if (!a.found || !b.found) return false
  if (a.nodeIds.length !== b.nodeIds.length) return false
  return a.nodeIds.every((id, i) => id === b.nodeIds[i])
}

// ============================================================
// Hook
// ============================================================

/**
 * Memoized hook that converts a PathResult into turn-by-turn walking directions.
 *
 * Returns an empty result when:
 * - pathResult is null
 * - pathResult.found is false
 * - pathResult has fewer than 2 nodeIds
 */
export function useRouteDirections(
  pathResult: PathResult | null,
  nodeMap: Map<string, NavNode>,
  mode: 'standard' | 'accessible',
  floorMap?: Map<number, NavFloor>,
): DirectionsResult {
  return useMemo(() => {
    if (pathResult === null || !pathResult.found) {
      return { steps: [], totalDistanceNorm: 0, totalDurationSec: 0 }
    }
    return generateDirections(pathResult.nodeIds, nodeMap, mode, floorMap)
  }, [pathResult, nodeMap, mode, floorMap])
}

import type { PathResult } from '@shared/pathfinding/types'
import type { NavFloor, NavNode } from '@shared/types'
import { describe, expect, it } from 'vitest'
import { type DirectionStep, generateDirections, routesAreIdentical } from './useRouteDirections'

// ---------------------------------------------------------------------------
// Minimal test fixtures
// ---------------------------------------------------------------------------

/**
 * Build a NavNode with defaults — only override what each test needs.
 */
function makeNode(id: string, x: number, y: number, overrides: Partial<NavNode> = {}): NavNode {
  return {
    id,
    x,
    y,
    label: id,
    type: 'hallway',
    searchable: false,
    floorId: 1,
    ...overrides,
  }
}

function makeMap(nodes: NavNode[]): Map<string, NavNode> {
  return new Map(nodes.map((n) => [n.id, n]))
}

// ---------------------------------------------------------------------------
// generateDirections — edge cases (0 and 1 nodes)
// ---------------------------------------------------------------------------

describe('generateDirections — empty/single node paths', () => {
  const nodeMap = makeMap([makeNode('a', 0, 0)])

  it('returns empty result for 0 nodes', () => {
    const result = generateDirections([], nodeMap, 'standard')
    expect(result.steps).toEqual([])
    expect(result.totalDistanceNorm).toBe(0)
    expect(result.totalDurationSec).toBe(0)
  })

  it('returns empty result for 1 node', () => {
    const result = generateDirections(['a'], nodeMap, 'standard')
    expect(result.steps).toEqual([])
    expect(result.totalDistanceNorm).toBe(0)
    expect(result.totalDurationSec).toBe(0)
  })
})

// ---------------------------------------------------------------------------
// generateDirections — 2-node path (single "arrive" step)
// ---------------------------------------------------------------------------

describe('generateDirections — 2-node path', () => {
  // a(0,0) → b(0.3,0)
  const a = makeNode('a', 0, 0)
  const b = makeNode('b', 0.3, 0, { label: 'Library', type: 'landmark', searchable: true })
  const nodeMap = makeMap([a, b])

  it('returns single arrive step', () => {
    const result = generateDirections(['a', 'b'], nodeMap, 'standard')
    expect(result.steps).toHaveLength(1)
    const step = result.steps[0] as DirectionStep
    expect(step.icon).toBe('arrive')
    expect(step.instruction).toContain('Library')
  })

  it('calculates correct durationSec for standard mode', () => {
    const WALKING_SPEED_STANDARD = 0.023
    const dist = 0.3 // Euclidean distance a→b
    const result = generateDirections(['a', 'b'], nodeMap, 'standard')
    const step = result.steps[0] as DirectionStep
    expect(step.durationSec).toBeCloseTo(dist / WALKING_SPEED_STANDARD, 2)
  })

  it('calculates correct durationSec for accessible mode', () => {
    const WALKING_SPEED_ACCESSIBLE = 0.013
    const dist = 0.3
    const result = generateDirections(['a', 'b'], nodeMap, 'accessible')
    const step = result.steps[0] as DirectionStep
    expect(step.durationSec).toBeCloseTo(dist / WALKING_SPEED_ACCESSIBLE, 2)
  })

  it('accumulates totalDistanceNorm and totalDurationSec', () => {
    const result = generateDirections(['a', 'b'], nodeMap, 'standard')
    expect(result.totalDistanceNorm).toBeCloseTo(0.3, 5)
    expect(result.totalDurationSec).toBeGreaterThan(0)
  })
})

// ---------------------------------------------------------------------------
// generateDirections — 3-node straight path (collinear)
// ---------------------------------------------------------------------------

describe('generateDirections — straight path (3 collinear nodes)', () => {
  // a(0,0.5) → b(0.5,0.5) → c(1,0.5) — all on the same horizontal line
  const a = makeNode('a', 0, 0.5)
  const b = makeNode('b', 0.5, 0.5)
  const c = makeNode('c', 1, 0.5, { label: 'Exit', type: 'entrance', searchable: true })
  const nodeMap = makeMap([a, b, c])

  it('produces 2 steps total', () => {
    const result = generateDirections(['a', 'b', 'c'], nodeMap, 'standard')
    expect(result.steps).toHaveLength(2)
  })

  it('first step icon is straight', () => {
    const result = generateDirections(['a', 'b', 'c'], nodeMap, 'standard')
    const step = result.steps[0] as DirectionStep
    expect(step.icon).toBe('straight')
  })

  it('second step icon is arrive', () => {
    const result = generateDirections(['a', 'b', 'c'], nodeMap, 'standard')
    const step = result.steps[1] as DirectionStep
    expect(step.icon).toBe('arrive')
  })

  it('arrive step instruction includes landmark label', () => {
    const result = generateDirections(['a', 'b', 'c'], nodeMap, 'standard')
    const step = result.steps[1] as DirectionStep
    expect(step.instruction).toContain('Exit')
  })
})

// ---------------------------------------------------------------------------
// generateDirections — left turn (~90° left)
// ---------------------------------------------------------------------------

describe('generateDirections — left turn path', () => {
  // a(0,0) → b(0.5,0) → c(0.5,0.5)
  // Going right along x, then turning down (south)
  // bearing prev→curr = 90° (east), bearing curr→next = 180° (south)
  // delta = 180 - 90 = 90° → but sign determines left/right
  // With atan2 coords: east=90°, south=180°
  // delta = next_bearing - prev_bearing = 180 - 90 = 90° (right turn)
  // Use a left turn: a(0,0.5) → b(0.5,0.5) → c(0.5,0)
  // prev→curr bearing = east (90°)
  // curr→next bearing = north (0°)
  // delta = 0 - 90 = -90° → left turn
  const a = makeNode('a', 0, 0.5)
  const b = makeNode('b', 0.5, 0.5)
  const c = makeNode('c', 0.5, 0, { label: 'Office', type: 'room', searchable: true })
  const nodeMap = makeMap([a, b, c])

  it('first step icon is turn-left', () => {
    const result = generateDirections(['a', 'b', 'c'], nodeMap, 'standard')
    const step = result.steps[0] as DirectionStep
    expect(step.icon).toBe('turn-left')
  })

  it('turn-left step instruction mentions landmark at turn node', () => {
    // b is hallway/not searchable — no landmark reference
    const result = makeMap([
      a,
      makeNode('b', 0.5, 0.5, { label: 'Cafeteria', type: 'landmark', searchable: true }),
      c,
    ])
    const directions = generateDirections(['a', 'b', 'c'], result, 'standard')
    const step = directions.steps[0] as DirectionStep
    expect(step.instruction).toContain('Cafeteria')
  })
})

// ---------------------------------------------------------------------------
// generateDirections — right turn (~90° right)
// ---------------------------------------------------------------------------

describe('generateDirections — right turn path', () => {
  // a(0,0.5) → b(0.5,0.5) → c(0.5,1)
  // prev→curr bearing = east (90°)
  // curr→next bearing = south (180°)
  // delta = 180 - 90 = 90° → right turn
  const a = makeNode('a', 0, 0.5)
  const b = makeNode('b', 0.5, 0.5)
  const c = makeNode('c', 0.5, 1)
  const nodeMap = makeMap([a, b, c])

  it('first step icon is turn-right', () => {
    const result = generateDirections(['a', 'b', 'c'], nodeMap, 'standard')
    const step = result.steps[0] as DirectionStep
    expect(step.icon).toBe('turn-right')
  })
})

// ---------------------------------------------------------------------------
// generateDirections — sharp turns (≥120°)
// ---------------------------------------------------------------------------

describe('generateDirections — sharp turns', () => {
  it('sharp-right: bearing delta >= 120° positive', () => {
    // a(0,0.5) → b(0.5,0.5) → c(0.356,0.705)
    // prev→curr bearing = east (90°)
    // curr→next bearing ≈ 215° (SSW) → delta ≈ 125° → sharp-right
    const a = makeNode('a', 0, 0.5)
    const b = makeNode('b', 0.5, 0.5)
    const c = makeNode('c', 0.356, 0.705) // bearing from b ≈ 215°, delta ≈ 125°
    const nodeMap = makeMap([a, b, c])
    const result = generateDirections(['a', 'b', 'c'], nodeMap, 'standard')
    const step = result.steps[0] as DirectionStep
    expect(step.icon).toBe('sharp-right')
  })
})

// ---------------------------------------------------------------------------
// generateDirections — isAccessibleSegment
// ---------------------------------------------------------------------------

describe('generateDirections — isAccessibleSegment', () => {
  it('marks ramp node as accessible segment', () => {
    const a = makeNode('a', 0, 0)
    const b = makeNode('b', 0.5, 0, { type: 'ramp' })
    const c = makeNode('c', 1, 0)
    const nodeMap = makeMap([a, b, c])
    const result = generateDirections(['a', 'b', 'c'], nodeMap, 'standard')
    const step = result.steps[0] as DirectionStep
    expect(step.isAccessibleSegment).toBe(true)
  })

  it('marks elevator node as accessible segment', () => {
    const a = makeNode('a', 0, 0)
    const b = makeNode('b', 0.5, 0, { type: 'elevator' })
    const c = makeNode('c', 1, 0)
    const nodeMap = makeMap([a, b, c])
    const result = generateDirections(['a', 'b', 'c'], nodeMap, 'standard')
    const step = result.steps[0] as DirectionStep
    expect(step.isAccessibleSegment).toBe(true)
  })

  it('hallway node is not accessible segment', () => {
    const a = makeNode('a', 0, 0)
    const b = makeNode('b', 0.5, 0, { type: 'hallway' })
    const c = makeNode('c', 1, 0)
    const nodeMap = makeMap([a, b, c])
    const result = generateDirections(['a', 'b', 'c'], nodeMap, 'standard')
    const step = result.steps[0] as DirectionStep
    expect(step.isAccessibleSegment).toBe(false)
  })
})

// ---------------------------------------------------------------------------
// Floor-change direction steps (new in 17-03)
// ---------------------------------------------------------------------------

/**
 * Build a minimal NavFloor with the given id and floorNumber.
 */
function makeFloor(id: number, floorNumber: number): NavFloor {
  return {
    id,
    floorNumber,
    imagePath: '',
    updatedAt: '',
    nodes: [],
    edges: [],
  }
}

/**
 * Build a Map<number, NavFloor> from an array of [id, floorNumber] pairs.
 */
function makeFloorMap(entries: [number, number][]): Map<number, NavFloor> {
  return new Map(entries.map(([id, floorNumber]) => [id, makeFloor(id, floorNumber)]))
}

describe('generateDirections — floor-change steps', () => {
  // Shared layout: a(0,0) → b(0.5,0) → c(1,0)
  // b is the connector node (stairs/elevator/ramp) on floor 1; c is on floor 2

  it('Test 1: stairs-up — curr on floor 1, next on floor 2', () => {
    const a = makeNode('a', 0, 0, { floorId: 1 })
    const b = makeNode('b', 0.5, 0, { type: 'stairs', floorId: 1 })
    const c = makeNode('c', 1, 0, { floorId: 2 })
    const floorMap = makeFloorMap([[1, 1], [2, 2]])
    const result = generateDirections(['a', 'b', 'c'], makeMap([a, b, c]), 'standard', floorMap)
    const step = result.steps[0] as DirectionStep
    expect(step.icon).toBe('stairs-up')
    expect(step.instruction).toBe('Take the stairs to Floor 2')
    expect(step.isAccessibleSegment).toBe(false)
  })

  it('Test 2: stairs-down — curr on floor 2, next on floor 1', () => {
    const a = makeNode('a', 0, 0, { floorId: 2 })
    const b = makeNode('b', 0.5, 0, { type: 'stairs', floorId: 2 })
    const c = makeNode('c', 1, 0, { floorId: 1 })
    const floorMap = makeFloorMap([[1, 1], [2, 2]])
    const result = generateDirections(['a', 'b', 'c'], makeMap([a, b, c]), 'standard', floorMap)
    const step = result.steps[0] as DirectionStep
    expect(step.icon).toBe('stairs-down')
    expect(step.instruction).toBe('Take the stairs to Floor 1')
  })

  it('Test 3: elevator floor change — isAccessibleSegment true', () => {
    const a = makeNode('a', 0, 0, { floorId: 1 })
    const b = makeNode('b', 0.5, 0, { type: 'elevator', floorId: 1 })
    const c = makeNode('c', 1, 0, { floorId: 2 })
    const floorMap = makeFloorMap([[1, 1], [2, 2]])
    const result = generateDirections(['a', 'b', 'c'], makeMap([a, b, c]), 'standard', floorMap)
    const step = result.steps[0] as DirectionStep
    expect(step.icon).toBe('elevator')
    expect(step.instruction).toBe('Take the elevator to Floor 2')
    expect(step.isAccessibleSegment).toBe(true)
  })

  it('Test 4: ramp floor change — isAccessibleSegment true', () => {
    const a = makeNode('a', 0, 0, { floorId: 1 })
    const b = makeNode('b', 0.5, 0, { type: 'ramp', floorId: 1 })
    const c = makeNode('c', 1, 0, { floorId: 2 })
    const floorMap = makeFloorMap([[1, 1], [2, 2]])
    const result = generateDirections(['a', 'b', 'c'], makeMap([a, b, c]), 'standard', floorMap)
    const step = result.steps[0] as DirectionStep
    expect(step.icon).toBe('ramp')
    expect(step.instruction).toBe('Take the ramp to Floor 2')
    expect(step.isAccessibleSegment).toBe(true)
  })

  it('Test 5: floorMap omitted — instruction falls back to floorId as floor number', () => {
    const a = makeNode('a', 0, 0, { floorId: 1 })
    const b = makeNode('b', 0.5, 0, { type: 'stairs', floorId: 1 })
    const c = makeNode('c', 1, 0, { floorId: 2 })
    // No floorMap passed — generateDirections uses undefined (empty Map default)
    const result = generateDirections(['a', 'b', 'c'], makeMap([a, b, c]), 'standard')
    const step = result.steps[0] as DirectionStep
    expect(step.icon).toBe('stairs-up')
    // Fallback: floorNumber ?? next.floorId → uses next.floorId = 2
    expect(step.instruction).toBe('Take the stairs to Floor 2')
  })

  it('Test 6: same-floor nodes — no floor-change step emitted', () => {
    // All nodes on floorId=1 — normal turn classification
    const a = makeNode('a', 0, 0.5, { floorId: 1 })
    const b = makeNode('b', 0.5, 0.5, { type: 'hallway', floorId: 1 })
    const c = makeNode('c', 1, 0.5, { floorId: 1 })
    const floorMap = makeFloorMap([[1, 1]])
    const result = generateDirections(['a', 'b', 'c'], makeMap([a, b, c]), 'standard', floorMap)
    const step = result.steps[0] as DirectionStep
    // Should be a straight step, not a floor-change step
    expect(step.icon).toBe('straight')
    expect(step.instruction).toBe('Continue straight')
  })
})

// ---------------------------------------------------------------------------
// routesAreIdentical
// ---------------------------------------------------------------------------

describe('routesAreIdentical', () => {
  const found = (nodeIds: string[]): PathResult => ({
    found: true,
    nodeIds,
    totalDistance: 1,
    segments: [],
  })

  const notFound: PathResult = {
    found: false,
    nodeIds: [],
    totalDistance: 0,
    segments: [],
  }

  it('returns true when both routes have same nodeIds', () => {
    expect(routesAreIdentical(found(['a', 'b', 'c']), found(['a', 'b', 'c']))).toBe(true)
  })

  it('returns false when nodeIds differ', () => {
    expect(routesAreIdentical(found(['a', 'b', 'c']), found(['a', 'b', 'd']))).toBe(false)
  })

  it('returns false when lengths differ', () => {
    expect(routesAreIdentical(found(['a', 'b']), found(['a', 'b', 'c']))).toBe(false)
  })

  it('returns false when first route not found', () => {
    expect(routesAreIdentical(notFound, found(['a', 'b']))).toBe(false)
  })

  it('returns false when second route not found', () => {
    expect(routesAreIdentical(found(['a', 'b']), notFound)).toBe(false)
  })

  it('returns false when both routes not found', () => {
    expect(routesAreIdentical(notFound, notFound)).toBe(false)
  })
})

